 4→
 5→export const OnboardingService = {
 6→  /** Check if a CLI tool is installed. Returns safe default on failure or in web mode. */
 7→  checkCliTool: native.cli.checkCliTool,
 8→
 9→  /** Check GitHub CLI auth status. Returns unauthenticated on failure or in web mode. */
10→  checkGhAuth: native.cli.checkGhAuth,
11→
12→  /** Fetch recent projects from Cursor, VS Code, and Claude directories. */
13→  async fetchRecentProjects(): Promise<{ projects: RecentProject[] }> {
