 3→import { queryKeys } from "@/shared/api/queryKeys";
 4→
 5→export function useCliCheck(toolName: string) {
 6→  return useQuery({
 7→    queryKey: ["onboarding", "cli-check", toolName],
 8→    queryFn: () => OnboardingService.checkCliTool(toolName),
 9→    staleTime: Infinity,
10→    retry: false,
11→  });
