14→export function useGhAuth(enabled: boolean) {
15→  return useQuery({
16→    queryKey: ["onboarding", "gh-auth"],
17→    queryFn: () => OnboardingService.checkGhAuth(),
18→    staleTime: Infinity,
19→    retry: false,
20→    enabled,
21→  });
22→}
23→
24→export function useRecentProjects() {
25→  return useQuery({
26→    queryKey: ["onboarding", "recent-projects"],
27→    queryFn: () => OnboardingService.fetchRecentProjects(),
28→    staleTime: Infinity,
29→    retry: false,
30→  });
31→}
