33→export function useCompleteOnboarding() {
34→  const queryClient = useQueryClient();
35→
36→  return useMutation({
37→    mutationFn: () => OnboardingService.completeOnboarding(),
38→    onSuccess: () => {
39→      queryClient.invalidateQueries({ queryKey: queryKeys.settings.all });
40→    },
41→  });
