  1→import { useState, useCallback } from "react";
  2→import { Loader2, FolderOpen } from "lucide-react";
  3→import { useRecentProjects } from "../../api";
  4→import { useAddRepo } from "@/features/repository/api";
  5→import { native } from "@/platform";
  6→import { capabilities } from "@/platform/capabilities";
  7→import { ProjectCard } from "../components/ProjectCard";
  8→
  9→interface ProjectSelectionStepProps {
 10→  onBack: () => void;
 11→  onNext: () => void;
 12→}
 13→
 14→export function ProjectSelectionStep({ onBack, onNext }: ProjectSelectionStepProps) {
 15→  const projectsQuery = useRecentProjects();
 16→  const addRepoMutation = useAddRepo();
 17→  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
 18→  const [importing, setImporting] = useState(false);
 19→
 20→  const projects = projectsQuery.data?.projects ?? [];
 21→
 22→  const toggleProject = useCallback((path: string) => {
 23→    setSelectedPaths((prev) => {
 24→      const next = new Set(prev);
 25→      if (next.has(path)) {
 26→        next.delete(path);
 27→      } else {
 28→        next.add(path);
 29→      }
 30→      return next;
 31→    });
 32→  }, []);
 33→
 34→  async function handleOpenProjects() {
 35→    if (selectedPaths.size === 0) return;
 36→    setImporting(true);
 37→    try {
 38→      for (const path of selectedPaths) {
 39→        try {
 40→          await addRepoMutation.mutateAsync(path);
 41→        } catch {
 42→          // Skip repos that fail (e.g. already added)
 43→        }
 44→      }
 45→      onNext();
 46→    } finally {
 47→      setImporting(false);
 48→    }
 49→  }
 50→
 51→  async function handleBrowse() {
 52→    try {
 53→      const folderPath = await native.dialog.pickFolder();
 54→      if (!folderPath) return;
 55→      setImporting(true);
 56→      await addRepoMutation.mutateAsync(folderPath);
 57→      onNext();
 58→    } catch {
 59→      // Dialog cancelled or failed
 60→    } finally {
 61→      setImporting(false);
 62→    }
 63→  }
 64→
 65→  return (
 66→    <div className="flex w-full max-w-lg flex-col gap-6">
 67→      <div className="space-y-2">
 68→        <h2 className="text-2xl font-semibold text-white">Your Projects</h2>
 69→        <p className="text-sm text-white/50">
 70→          Select projects to add to OpenDevs, or browse for a folder.
 71→        </p>
 72→      </div>
 73→
 74→      {projectsQuery.isLoading ? (
 75→        <div className="flex items-center justify-center py-12">
 76→          <Loader2 className="h-5 w-5 animate-spin text-white/30" />
 77→        </div>
 78→      ) : projects.length === 0 ? (
 79→        <div className="flex flex-col items-center gap-3 py-12 text-center">
 80→          <FolderOpen className="h-8 w-8 text-white/20" />
 81→          <p className="text-sm text-white/40">No recent projects found. Browse to add one.</p>
 82→        </div>
 83→      ) : (
 84→        <div
 85→          className="scrollbar-vibrancy flex max-h-[320px] flex-col gap-2 overflow-y-auto pr-1"
 86→          style={{
 87→            maskImage:
 88→              "linear-gradient(to bottom, transparent, black 24px, black calc(100% - 32px), transparent)",
 89→            WebkitMaskImage:
 90→              "linear-gradient(to bottom, transparent, black 24px, black calc(100% - 32px), transparent)",
 91→          }}
 92→        >
 93→          {projects.map((project) => (
 94→            <ProjectCard
 95→              key={project.path}
 96→              project={project}
 97→              selected={selectedPaths.has(project.path)}
 98→              onToggle={toggleProject}
 99→            />
100→          ))}
101→        </div>
102→      )}
103→
104→      <div className="flex items-center gap-3 pt-2">
105→        <button
106→          onClick={onBack}
107→          className="rounded-xl px-6 py-2.5 text-sm font-medium text-white/50 transition-colors duration-200 hover:text-white/80"
108→        >
109→          Back
110→        </button>
111→        <div className="flex-1" />
112→        <button
113→          onClick={onNext}
114→          className="rounded-xl bg-white/10 px-6 py-2.5 text-sm font-medium text-white/70 transition-colors duration-200 hover:bg-white/15 hover:text-white"
115→        >
116→          Skip
117→        </button>
118→        {capabilities.nativeFolderPicker && (
119→          <button
120→            onClick={handleBrowse}
121→            disabled={importing}
122→            className="rounded-xl bg-white/10 px-6 py-2.5 text-sm font-medium text-white/70 transition-colors duration-200 hover:bg-white/15 hover:text-white disabled:opacity-50"
123→          >
124→            Browse...
125→          </button>
126→        )}
127→        {selectedPaths.size > 0 && (
128→          <button
