 26→const app = new Hono();
 27→
 28→app.get("/repos", (c) => {
 29→  const db = getDatabase();
 30→  return c.json(getAllRepositories(db));
 31→});
 32→
 33→app.post("/repos", async (c) => {
 34→  const db = getDatabase();
 35→  let { root_path } = parseBody(CreateRepoBody, await c.req.json());
 36→
 37→  // Normalize path
 38→  try {
 39→    root_path = fs.realpathSync(root_path);
 40→  } catch {
 41→    throw new ValidationError("Path does not exist or is inaccessible");
 42→  }
 43→
 44→  // Verify permissions
 45→  try {
 46→    fs.accessSync(root_path, fs.constants.R_OK | fs.constants.X_OK);
 47→  } catch {
 48→    throw new AppError(403, "Path is not accessible (permission denied)");
 49→  }
 50→
 51→  const stats = fs.statSync(root_path);
 52→  if (!stats.isDirectory()) throw new ValidationError("Path is not a directory");
 53→
 54→  // Check git repo and resolve to repo root
 55→  try {
 56→    root_path = execFileSync("git", ["rev-parse", "--show-toplevel"], {
 57→      cwd: root_path,
 58→      timeout: 2000,
 59→    })
 60→      .toString()
 61→      .trim();
 62→  } catch {
 63→    throw new ValidationError("Path is not a git repository");
 64→  }
 65→
 66→  const repoName = path.basename(root_path);
 67→  const defaultBranch = detectDefaultBranch(root_path);
 68→
 69→  const insertRepo = db.transaction(
 70→    (root_path: string, repoId: string, repoName: string, defaultBranch: string) => {
 71→      const existing = getRepositoryByRootPath(db, root_path);
 72→      if (existing) throw new ConflictError("Repository already exists", existing);
 73→
 74→      const sortOrder = getMaxRepositorySortOrder(db) + 1;
 75→
 76→      db.prepare(
 77→        `
 78→      INSERT INTO repositories (id, name, root_path, git_default_branch, sort_order)
 79→      VALUES (?, ?, ?, ?, ?)
 80→    `
 81→      ).run(repoId, repoName, root_path, defaultBranch, sortOrder);
 82→
 83→      return getRepositoryById(db, repoId);
 84→    }
 85→  );
 86→
 87→  const repoId = uuidv7();
 88→  const repo = insertRepo(root_path, repoId, repoName, defaultBranch);
 89→  invalidate(["stats"] as QueryResource[]);
 90→  return c.json(repo, 201);
 91→});
