 97→  const db = getDatabase();
 98→  const repo = getRepositoryById(db, c.req.param("id"));
 99→  if (!repo) throw new NotFoundError("Repository not found");
100→
101→  const manifest = readManifest(repo.root_path);
102→  if (!manifest) return c.json({ manifest: null, tasks: [] });
103→  const tasks = getNormalizedTasks(manifest);
104→  return c.json({ manifest, tasks });
105→});
