107→// Write manifest to repo root
108→app.post("/repos/:id/manifest", async (c) => {
109→  const db = getDatabase();
110→  const repo = getRepositoryById(db, c.req.param("id"));
111→  if (!repo) throw new NotFoundError("Repository not found");
112→
113→  const manifest = parseBody(OpenDevsManifestSchema, await c.req.json());
114→  const success = writeManifest(repo.root_path, manifest);
115→  if (!success) return c.json({ error: "Failed to write manifest" }, 500);
116→  return c.json({ success: true });
117→});
