54→
55→  return useMutation({
56→    mutationFn: ({ repoId, manifest }: { repoId: string; manifest: Record<string, unknown> }) =>
57→      RepoService.saveManifest(repoId, manifest),
58→    onSuccess: (_data, { repoId }) => {
59→      queryClient.invalidateQueries({ queryKey: queryKeys.repos.manifest(repoId) });
60→      // Also invalidate workspace manifests since they inherit from repo
61→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
62→    },
63→  });
