66→/**
67→ * Add repository mutation
68→ */
69→export function useAddRepo() {
70→  const queryClient = useQueryClient();
71→
72→  return useMutation({
73→    mutationFn: (rootPath: string) => RepoService.add(rootPath),
74→    onSuccess: (_data, rootPath) => {
75→      track("repo_added", { repo_name: rootPath.split("/").pop() });
76→      // Invalidate repos and workspaces (new repo means new potential workspaces)
77→      queryClient.invalidateQueries({ queryKey: queryKeys.repos.all });
78→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
79→    },
80→  });
