311→function handleUnsubscribe(connectionId: string, msg: UnsubscribeFrameInput): void {
312→  const { id } = msg;
313→
314→  const connSubs = subs.get(connectionId);
315→  if (!connSubs) return;
316→
317→  const sub = connSubs.get(id);
318→  if (sub) {
319→    // Clean up message cursor
320→    if (sub.resource === "messages") {
321→      messageCursors.delete(`${connectionId}:${id}`);
322→    }
323→    connSubs.delete(id);
324→    if (connSubs.size === 0) subs.delete(connectionId);
325→  }
326→}
