 16→// ─── Timeline ───────────────────────────────────────────────────────────────
 17→//
 18→// Agent Dots SVG (~10s at 30fps):
 19→//   Phase 1 (0–2s):    Center dot breathes
 20→//   Phase 2 (2–6s):    Rings spawn + vortex spin
 21→//   Phase 3 (6–7s):    "The Pull" — dots converge, center expands
 22→//
 23→// Transition (staggered):
 24→//   The white circle fills the screen by ~6.7s (cover mode). We start fading
 25→//   at 6.5s — the white is growing but hasn't taken over yet. The card
 26→//   enters 350ms later, once the white has dissolved enough to not blind.
 27→//
 28→//   6.0s    6.7s       7.05s       7.4s
 29→//    │       ├─ fade ───────────────┤  (700ms, opacity 1→0)
 30→//    │       │          ├─ card ────┤  (420ms, CSS enter anim)
 31→//    │       │          │           │
 32→//    pull    fade       card in     anim unmounts
 33→//    starts  starts     350ms gap   card fully visible
 34→//
 35→const TIMELINE = {
 36→  MUSIC_START: 450,
 37→  INTRO_COMPLETE: 6700, // Let white expansion show more before fading
 38→  CARD_DELAY: 350, // Gap before card — let white dissolve first
 39→  FADE_DURATION: 700, // Moderate fade while center still expanding
 40→  EXIT_DURATION: 900, // Exit animation before window restore
 41→} as const;
 42→
 43→const TOTAL_STEPS = 5;
 44→const OVERLAY_BG = "oklch(0.06 0.005 264 / 0.52)";
 45→
 46→// Card surface — no border. Light and shadow define form, not lines.
 47→// Top inset highlight mimics an edge-lit surface (like brushed aluminium
 48→// catching light from above). Two-layer shadow: close contact shadow for
 49→// grounding + large diffuse shadow for atmospheric depth.
 50→const CARD_STYLE = {
 51→  background: "oklch(0.13 0.012 264 / 0.92)",
 52→  backdropFilter: "blur(40px) saturate(1.4)",
 53→  WebkitBackdropFilter: "blur(40px) saturate(1.4)",
 54→  boxShadow: [
 55→    "inset 0 0.5px 0 0 oklch(1 0 0 / 0.06)",
 56→    "0 8px 20px -4px oklch(0 0 0 / 0.25)",
 57→    "0 24px 68px -12px oklch(0 0 0 / 0.5)",
 58→  ].join(", "),
 59→} as const;
