 98→    if (onboardingStartRef.current === 0) {
 99→      onboardingStartRef.current = Date.now();
100→    }
101→  }, []);
102→
103→  // Idempotent — starts fade, then brings card in after a short delay.
104→  // The stagger lets the white circle dissolve before the card appears,
105→  // so the user sees: expanding white → dissolving glow → card emerges.
106→  const completeIntro = useCallback(() => {
107→    if (introCompletedRef.current) return;
108→    introCompletedRef.current = true;
109→
110→    setAnimationFading(true);
111→    setTimeout(() => {
112→      setShowCard(true); // Card enters once white has partly dissolved
113→    }, TIMELINE.CARD_DELAY);
114→    setTimeout(() => {
115→      setShowAnimation(false); // Unmount SVG after fully transparent
116→    }, TIMELINE.FADE_DURATION);
117→  }, []);
