119→  // ── Enter/exit onboarding mode (StrictMode-safe) ────────────────────
120→  // React 18 StrictMode double-mounts: mount → unmount → remount.
121→  // No ref guard — let enter run every mount. The native code is idempotent
122→  // (saves frame only once, restores on exit, re-saves on next enter).
123→  // Sequence in StrictMode: enter → exit → enter → stays entered. ✅
124→  useEffect(() => {
125→    if (capabilities.nativeOnboarding) {
126→      native.window.enterOnboarding().catch((e) => {
127→        console.error("[Onboarding] enter_onboarding_mode failed:", e);
128→      });
129→    } else {
