132→    }
133→
134→    return () => {
135→      // On real unmount (or StrictMode simulated unmount): restore everything.
136→      // StrictMode re-mount will call enter again, which is correct.
137→      audio.stop();
138→      if (!exitHandledRef.current) {
139→        if (capabilities.nativeOnboarding) {
140→          native.window.exitOnboarding().catch((e) => {
