149→  }, []); // eslint-disable-line react-hooks/exhaustive-deps -- audio.stop() in cleanup is intentional; audio ref is stable
150→
151→  // ── Analytics: track onboarding start (StrictMode-safe) ──────────────
152→  const onboardingTrackedRef = useRef(false);
153→  useEffect(() => {
154→    if (onboardingTrackedRef.current) return;
