 26→/**
 27→ * Detects whether a git_clone error means the repo already exists on disk.
 28→ *
 29→ * git_clone returns several variants depending on the code path:
 30→ *   - "already contains a git repository" -- .git dir found in target (pre-clone check)
 31→ *   - "already exists and is not empty" -- non-empty target dir without .git
 32→ *   - "already exists" -- git CLI stderr when target dir exists
 33→ *   - "destination path ... already exists" -- another git CLI stderr variant
 34→ */
 35→function isAlreadyClonedError(message: string): boolean {
 36→  return (
 37→    message.includes("already contains") ||
 38→    message.includes("already exists") ||
 39→    message.includes("destination path")
 40→  );
 41→}
 42→
 43→/**
 44→ * Fire-and-forget: clone repo, register in DB, invalidate queries.
 45→ *
 46→ * Runs independently of React component lifecycle -- safe to call then unmount.
 47→ * Uses only singletons: invoke, RepoService, queryClient, toast.
 48→ * On success the repo appears in the sidebar via query invalidation.
 49→ * On failure a toast tells the user what happened (the <Toaster> mounts
 50→ * in App.tsx after onboarding completes, well before this async work finishes).
 51→ */
 52→async function cloneAndRegisterInBackground() {
 53→  try {
 54→    const home = await native.dialog.getHomeDir();
 55→    const target = `${home}/Developer/${REPO.name}`;
 56→
 57→    // Phase 1: Clone (or detect already-cloned)
 58→    let alreadyCloned = false;
 59→    try {
 60→      const baseUrl = await getBackendUrl();
 61→      const res = await fetch(`${baseUrl}/api/repos/clone`, {
 62→        method: "POST",
 63→        headers: { "Content-Type": "application/json" },
 64→        body: JSON.stringify({ url: REPO.url, targetPath: target }),
 65→      });
 66→      if (!res.ok) {
 67→        const err = await res.json().catch(() => ({ error: "Clone failed" }));
 68→        throw new Error(err.error || `HTTP ${res.status}`);
 69→      }
 70→    } catch (err) {
 71→      const message = getErrorMessage(err);
 72→      if (!isAlreadyClonedError(message)) {
 73→        console.error("[OpenDevs] Clone failed:", message);
 74→        toast.error("Couldn\u2019t clone OpenDevs. You can add it later from the sidebar.");
 75→        return;
 76→      }
 77→      alreadyCloned = true;
 78→    }
 79→
 80→    // Phase 2: Register in DB (idempotent -- 409 = already registered)
 81→    let repoId: string | null = null;
 82→    try {
 83→      const repo = await RepoService.add(target);
 84→      repoId = repo.id;
 85→    } catch (err) {
 86→      // ApiError shape from client.ts: { status, message, details: <response body> }
 87→      // 409 response body: { error: "...", details: { id, name, ... } }
 88→      const apiErr = err as { status?: number; details?: { details?: unknown } };
 89→      if (apiErr?.status === 409) {
 90→        const existing = apiErr.details?.details;
 91→        if (existing && typeof existing === "object" && "id" in existing) {
 92→          repoId = (existing as { id: string }).id;
 93→        }
 94→        if (!repoId) {
 95→          console.warn("[OpenDevs] 409 conflict but couldn't extract repo ID:", err);
 96→        }
 97→      } else {
 98→        console.error("[OpenDevs] Register failed:", err);
 99→        toast.error(
100→          'OpenDevs cloned but couldn\u2019t register. Use "Add Repository" in the sidebar.'
101→        );
102→        return;
103→      }
104→    }
105→
106→    // Phase 3: Create workspace so repo appears in the sidebar.
107→    // The sidebar only shows repos that have at least one workspace.
108→    if (repoId) {
109→      try {
110→        await WorkspaceService.create(repoId);
111→      } catch {
112→        // Workspace creation failed -- repo is registered, user can create manually.
113→        // Don't block the success toast; the repo exists and can be used.
114→        console.warn("[OpenDevs] Workspace creation failed, repo still registered");
115→      }
116→    }
117→
118→    // Phase 4: Refresh sidebar so the new repo + workspace appear
119→    queryClient.invalidateQueries({ queryKey: queryKeys.repos.all });
120→    queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
121→
122→    toast.success(alreadyCloned ? "OpenDevs repository added" : "OpenDevs cloned and ready");
123→  } catch (err) {
124→    console.error("[OpenDevs] Background clone error:", err);
125→    toast.error("Something went wrong cloning OpenDevs.");
126→  }
127→}
128→
