  1→/**
  2→ * Workspace Initialization Pipeline
  3→ *
  4→ * Orchestrates the multi-step process of creating a workspace:
  5→ *   1. git worktree add (fatal — cleanup on failure)
  6→ *   2. Dependency installation via lockfile-detected PM (non-fatal)
  7→ *   3. Post-create hooks: .env / .env.local copy (non-fatal)
  8→ *   4. Git clean: restore tracked files so diff starts at zero (non-fatal)
  9→ *   5. Session creation + state transition to 'ready' (fatal)
 10→ *
 11→ * Each step updates the workspace's `init_stage` column in DB and emits
 12→ * a structured stdout line that Electron main process parses and relays as an IPC event:
 13→ *   OPENDEVS_WORKSPACE_PROGRESS:{"workspaceId":"...","step":"...","label":"..."}
 14→ *
 15→ * Design decisions:
 16→ * - Pipeline runs in-process (async), not as spawned child — proper try/catch
 17→ * - Non-fatal steps (deps, hooks) log warnings but don't block workspace creation
 18→ * - Reverse-order cleanup on fatal failure: rm dir → prune worktree → delete branch
 19→ * - Structured init pipeline with deps install
 20→ */
 21→
 22→import fs from "fs";
 23→import path from "path";
 24→import { execFile } from "child_process";
 25→import { promisify } from "util";
 26→import { uuidv7 } from "@shared/lib/uuid";
 27→import { getDatabase } from "../lib/database";
 28→import { invalidate } from "./query-engine";
 29→
 30→const execFileAsync = promisify(execFile);
 31→
 32→/** Check if an error is a retryable SQLite concurrency error (BUSY / locked). */
 33→export function isRetryableDbError(err: unknown): boolean {
 34→  if (!(err instanceof Error)) return false;
 35→  const msg = err.message.toLowerCase();
 36→  return (
 37→    msg.includes("sqlite_busy") ||
 38→    msg.includes("database is locked") ||
 39→    msg.includes("database is busy")
 40→  );
 41→}
 42→
 43→// ─── Types ──────────────────────────────────────────────────────
 44→
 45→export interface InitContext {
 46→  workspaceId: string;
 47→  repositoryId: string;
 48→  repoRootPath: string;
 49→  workspacePath: string;
 50→  branchName: string;
 51→  worktreeBase: string;
 52→  parentBranch: string;
 53→}
 54→
 55→interface InitStage {
 56→  name: string;
 57→  label: string;
 58→  fatal: boolean;
 59→  run: (ctx: InitContext) => Promise<void>;
 60→  cleanup?: (ctx: InitContext) => Promise<void>;
 61→}
 62→
 63→// ─── Progress Emission ──────────────────────────────────────────
 64→
 65→/**
 66→ * Emit workspace init progress via stdout JSON protocol.
 67→ * Electron's backend-process.ts reads stdout line-by-line and relays lines
 68→ * prefixed with OPENDEVS_WORKSPACE_PROGRESS: as IPC events.
 69→ */
 70→export function emitProgress(workspaceId: string, step: string, label: string): void {
 71→  const payload = JSON.stringify({ workspaceId, step, label });
 72→  process.stdout.write(`OPENDEVS_WORKSPACE_PROGRESS:${payload}\n`);
 73→}
 74→
 75→function updateInitStage(workspaceId: string, stage: string): void {
 76→  const db = getDatabase();
 77→  db.prepare("UPDATE workspaces SET init_stage = ? WHERE id = ?").run(stage, workspaceId);
 78→}
 79→
 80→// ─── Package Manager Detection ──────────────────────────────────
 81→
 82→interface PackageManager {
 83→  command: string;
 84→  args: string[];
 85→}
 86→
 87→/**
 88→ * Detect the package manager from lockfile presence in the workspace.
 89→ * Returns null if no package.json exists (nothing to install).
 90→ */
 91→export function detectPackageManager(dir: string): PackageManager | null {
 92→  // Check lockfiles in priority order (bun first — project default)
 93→  if (fs.existsSync(path.join(dir, "bun.lock")) || fs.existsSync(path.join(dir, "bun.lockb"))) {
 94→    return { command: "bun", args: ["install", "--frozen-lockfile"] };
 95→  }
 96→  if (fs.existsSync(path.join(dir, "yarn.lock"))) {
 97→    return { command: "yarn", args: ["install", "--frozen-lockfile"] };
 98→  }
 99→  if (fs.existsSync(path.join(dir, "pnpm-lock.yaml"))) {
100→    return { command: "pnpm", args: ["install", "--frozen-lockfile"] };
101→  }
102→  if (fs.existsSync(path.join(dir, "package-lock.json"))) {
103→    return { command: "npm", args: ["ci"] };
104→  }
105→  // package.json exists but no lockfile — try npm install
106→  if (fs.existsSync(path.join(dir, "package.json"))) {
107→    return { command: "npm", args: ["install"] };
108→  }
109→  return null;
110→}
111→
112→// ─── Cleanup ────────────────────────────────────────────────────
113→
114→async function cleanupWorktree(
115→  repoRootPath: string,
116→  workspacePath: string,
117→  branchName: string
118→): Promise<void> {
119→  // Remove worktree directory
120→  try {
121→    if (fs.existsSync(workspacePath)) {
122→      fs.rmSync(workspacePath, { recursive: true, force: true });
123→    }
124→  } catch (e) {
125→    console.warn("[WORKSPACE] Failed to remove worktree directory:", e);
126→  }
127→
128→  // Prune git worktree references
129→  try {
130→    await execFileAsync("git", ["worktree", "prune"], {
131→      cwd: repoRootPath,
132→      timeout: 5_000,
133→    });
134→  } catch (e) {
135→    console.warn("[WORKSPACE] Failed to prune worktrees:", e);
136→  }
137→
138→  // Delete the orphaned branch
139→  try {
140→    await execFileAsync("git", ["branch", "-D", branchName], {
141→      cwd: repoRootPath,
142→      timeout: 5_000,
143→    });
144→  } catch {
145→    // Branch may not have been created — that's fine
146→  }
147→}
148→
149→// ─── Pipeline Stages ────────────────────────────────────────────
150→
151→const STAGES: InitStage[] = [
152→  {
153→    name: "worktree",
154→    label: "Creating worktree...",
155→    fatal: true,
156→    async run(ctx) {
157→      await execFileAsync(
158→        "git",
159→        ["worktree", "add", "-b", ctx.branchName, ctx.workspacePath, ctx.worktreeBase],
160→        { cwd: ctx.repoRootPath, timeout: 30_000 }
161→      );
162→    },
163→    async cleanup(ctx) {
164→      await cleanupWorktree(ctx.repoRootPath, ctx.workspacePath, ctx.branchName);
165→    },
166→  },
167→  {
168→    name: "dependencies",
169→    label: "Installing dependencies...",
170→    fatal: false,
171→    async run(ctx) {
172→      const pm = detectPackageManager(ctx.workspacePath);
173→      if (!pm) {
174→        console.log("[WORKSPACE] No package.json found, skipping dependency install");
175→        return;
176→      }
177→      console.log(`[WORKSPACE] Installing dependencies with ${pm.command}...`);
178→      await execFileAsync(pm.command, pm.args, {
179→        cwd: ctx.workspacePath,
180→        timeout: 120_000, // 2 min max for large installs
181→        env: { ...process.env, CI: "1" }, // Suppress interactive prompts
182→      });
183→    },
184→  },
185→  {
186→    name: "hooks",
187→    label: "Setting up environment...",
188→    fatal: false,
189→    async run(ctx) {
190→      // Copy .env from repo root if it exists and worktree doesn't have one
191→      const envFiles = [".env", ".env.local"];
192→      for (const envFile of envFiles) {
193→        const src = path.join(ctx.repoRootPath, envFile);
194→        const dst = path.join(ctx.workspacePath, envFile);
195→        if (fs.existsSync(src) && !fs.existsSync(dst)) {
196→          try {
197→            fs.copyFileSync(src, dst);
198→            console.log(`[WORKSPACE] Copied ${envFile} to worktree`);
199→          } catch (e) {
200→            console.warn(`[WORKSPACE] Failed to copy ${envFile}:`, e);
201→          }
202→        }
203→      }
204→    },
205→  },
206→  {
207→    name: "git-clean",
208→    label: "Verifying workspace...",
209→    fatal: false,
210→    async run(ctx) {
211→      // After deps install and .env copy, the working directory may have
212→      // tracked-file modifications (e.g., lockfile normalization by the
213→      // package manager, generated build cache files). Reset tracked files
214→      // to match the index so the diff pipeline sees zero changes on a
215→      // fresh workspace branched from origin/main.
216→      await execFileAsync("git", ["checkout", "--", "."], {
217→        cwd: ctx.workspacePath,
218→        timeout: 10_000,
219→      });
220→    },
221→  },
222→  {
223→    name: "session",
224→    label: "Finalizing...",
225→    fatal: true,
226→    async run(ctx) {
227→      // Retry with exponential backoff to handle SQLITE_BUSY / database-locked
228→      // errors that can occur when the sidecar is concurrently accessing the DB.
229→      const db = getDatabase();
230→      const sessionId = uuidv7();
231→      const maxAttempts = 3;
232→
233→      for (let attempt = 1; attempt <= maxAttempts; attempt++) {
234→        try {
235→          const finalize = db.transaction(() => {
236→            db.prepare(
237→              "INSERT INTO sessions (id, workspace_id, status, updated_at) VALUES (?, ?, 'idle', datetime('now'))"
238→            ).run(sessionId, ctx.workspaceId);
239→            db.prepare(
240→              "UPDATE workspaces SET state = 'ready', current_session_id = ?, init_stage = 'done' WHERE id = ?"
241→            ).run(sessionId, ctx.workspaceId);
242→          });
243→          finalize();
244→          return;
245→        } catch (err) {
246→          if (attempt < maxAttempts && isRetryableDbError(err)) {
247→            const delay = Math.pow(2, attempt) * 100; // 200ms, 400ms
248→            console.warn(
249→              `[WORKSPACE] Session creation attempt ${attempt}/${maxAttempts} failed (${(err as Error).message}), retrying in ${delay}ms...`
250→            );
251→            await new Promise((r) => setTimeout(r, delay));
252→          } else {
253→            throw err;
254→          }
255→        }
256→      }
257→    },
258→  },
259→];
260→
261→// ─── Pipeline Runner ────────────────────────────────────────────
262→
263→export async function initializeWorkspace(ctx: InitContext): Promise<void> {
264→  const completed: InitStage[] = [];
265→
266→  for (const stage of STAGES) {
267→    try {
268→      updateInitStage(ctx.workspaceId, stage.name);
269→    } catch (err) {
270→      // SQLITE_BUSY can fire when sidecar holds the DB — log but don't
271→      // abort, otherwise cleanup never runs and worktrees leak.
272→      console.warn("[WORKSPACE] Failed to update init_stage:", err);
273→    }
274→    emitProgress(ctx.workspaceId, stage.name, stage.label);
275→
276→    try {
277→      await stage.run(ctx);
278→      completed.push(stage);
279→    } catch (err) {
280→      console.error(`[WORKSPACE] Stage "${stage.name}" failed:`, err);
281→
282→      if (stage.fatal) {
283→        // Reverse-order cleanup of completed stages
284→        for (const done of [...completed].reverse()) {
285→          if (done.cleanup) {
286→            await done
287→              .cleanup(ctx)
288→              .catch((e) => console.warn(`[WORKSPACE] Cleanup for "${done.name}" failed:`, e));
289→          }
290→        }
291→
292→        const db = getDatabase();
293→        db.prepare(
294→          "UPDATE workspaces SET state = 'error', init_stage = ?, error_message = ? WHERE id = ?"
295→        ).run(stage.name, (err as Error).message, ctx.workspaceId);
296→
297→        emitProgress(ctx.workspaceId, "error", `Failed at: ${stage.name}`);
298→
299→        // Workspace transitioned to 'error' — notify connected clients.
300→        invalidate(["workspaces", "stats"]);
301→        return;
302→      }
303→      // Non-fatal: log and continue to next stage
304→      console.warn(`[WORKSPACE] Non-fatal stage "${stage.name}" failed, continuing...`);
305→    }
306→  }
307→
308→  emitProgress(ctx.workspaceId, "done", "Ready");
309→
310→  // Workspace transitioned to 'ready' — push to all connected clients.
311→  // Query-protocol subscribers get fresh snapshots + q:invalidate for unmounted caches.
312→  invalidate(["workspaces", "stats", "sessions"]);
313→}
